--procedimiento para eliminar de la tabla salud_ren_rec, registros que no de ben tener el aumento.
--30/07/2024

DROP procedure sp_jean17;
CREATE procedure sp_jean17()
RETURNING char(20);



{char(5) as cod_agente,
char(3) as z_vta_gral_ant,
char(3) as z_vta_gral_act,
char(3) as z_vta_persona_act;}
		  

DEFINE _cod_contratante,_no_poliza 	CHAR(10);
DEFINE _no_documento,_no_documento2        CHAR(20);
define _aumento,_montoaumento,_primanueva dec(16,2);
define _cod_agente       char(5);
define _cod_vendedor,_cod_vendedor2,_cod_vendedor_ant char(3);
define _error integer;
define _error_desc char(50);

{foreach
	select no_documento,
	       cod_asegurado
	  into _no_documento,
		   _cod_contratante
	  from deivid_tmp:am_salud

	delete from deivid_tmp:salud_ren_rec
	 where poliza       = _no_documento
	   and codasegurado = _cod_contratante;

end foreach}

{foreach
	select cod_agente,
	       cod_vendedor,
		   cod_vendedor2
	  into _cod_agente,
		   _cod_vendedor,
		   _cod_vendedor2
	  from deivid_tmp:act_zona
	  
	select cod_vendedor
	  into _cod_vendedor_ant
	  from agtagent
     where cod_agente = _cod_agente;

	update agtagent
	   set cod_vendedor  = _cod_vendedor,
	       cod_vendedor2 = _cod_vendedor2
	 where cod_agente = _cod_agente;
	 
	return _cod_agente,_cod_vendedor_ant,_cod_vendedor,_cod_vendedor2 with resume;

end foreach

return '','','','';}

